// SPDX-License-Identifier: MIT
// Copyright (c) 2024-2026 Askend Lab

import {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  ReactNode,
} from "react";

import { AuthStorage } from "./storage";
import {
  getLoginUrl,
  getLogoutUrl,
  getTaraLoginUrl,
  cognitoConfig,
  exchangeCodeForTokens,
} from "./config";
import type { AuthContextValue, AuthState, User } from "./types";

const initialState: AuthState = {
  user: null,
  isAuthenticated: false,
  isLoading: true,
  error: null,
};

const AuthContext = createContext<AuthContextValue | null>(null);

interface AuthProviderProps {
  children: ReactNode;
}

/**
 * Parse JWT id_token payload. Note: signature verification is not performed client-side
 * because tokens are obtained directly from Cognito over HTTPS. Server-side APIs should
 * verify tokens independently using Cognito's JWKS endpoint.
 */
function parseIdToken(idToken: string): User | null {
  try {
    const parts = idToken.split(".");
    if (parts.length !== 3 || !parts[1]) return null;
    const payload = JSON.parse(atob(parts[1]));

    // Validate required claims
    if (!payload.sub || typeof payload.sub !== "string") return null;
    if (payload.exp && Date.now() / 1000 > payload.exp) return null;

    return {
      id: payload.sub,
      email: payload.email,
      name: payload.name ?? payload.email?.split("@")[0],
    };
  } catch {
    return null;
  }
}

function isTokenExpired(token: string, bufferSeconds = 300): boolean {
  try {
    const parts = token.split(".");
    if (parts.length !== 3 || !parts[1]) return true;
    const payload = JSON.parse(atob(parts[1]));
    const exp = payload.exp;
    if (!exp) return true;
    return Date.now() / 1000 > exp - bufferSeconds;
  } catch {
    return true;
  }
}

async function refreshTokens(): Promise<boolean> {
  const refreshToken = AuthStorage.getRefreshToken();
  if (!refreshToken) return false;

  try {
    const response = await fetch(
      `https://${cognitoConfig.domain}/oauth2/token`,
      {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: new URLSearchParams({
          grant_type: "refresh_token",
          client_id: cognitoConfig.clientId,
          refresh_token: refreshToken,
        }),
      },
    );

    if (!response.ok) {
      return false;
    }

    const data = await response.json();
    AuthStorage.setAccessToken(data.access_token);
    if (data.id_token) {
      AuthStorage.setIdToken(data.id_token);
    }
    return true;
  } catch {
    return false;
  }
}

export function AuthProvider({ children }: AuthProviderProps) {
  const [state, setState] = useState<AuthState>(initialState);
  const [showLoginModal, setShowLoginModal] = useState(false);

  useEffect(() => {
    async function initAuth() {
      const storedUser = AuthStorage.getUser();
      const accessToken = AuthStorage.getAccessToken();

      if (storedUser && accessToken) {
        if (isTokenExpired(accessToken)) {
          const refreshed = await refreshTokens();
          if (refreshed) {
            setState({
              user: storedUser,
              isAuthenticated: true,
              isLoading: false,
              error: null,
            });
          } else {
            AuthStorage.clear();
            setState({ ...initialState, isLoading: false });
          }
        } else {
          setState({
            user: storedUser,
            isAuthenticated: true,
            isLoading: false,
            error: null,
          });
        }
      } else {
        setState({ ...initialState, isLoading: false });
      }
    }
    void initAuth();
  }, []);

  const login = useCallback(async () => {
    window.location.href = await getLoginUrl();
  }, []);

  const loginWithTara = useCallback(() => {
    window.location.href = getTaraLoginUrl();
  }, []);

  const logout = useCallback(async () => {
    AuthStorage.clear();
    setState({
      user: null,
      isAuthenticated: false,
      isLoading: false,
      error: null,
    });
    window.location.href = getLogoutUrl();
  }, []);

  const handleCodeCallback = useCallback(
    async (code: string): Promise<boolean> => {
      const tokens = await exchangeCodeForTokens(code);
      if (!tokens) return false;

      const user = parseIdToken(tokens.idToken);
      if (user) {
        AuthStorage.setUser(user);
        AuthStorage.setAccessToken(tokens.accessToken);
        AuthStorage.setIdToken(tokens.idToken);
        AuthStorage.setRefreshToken(tokens.refreshToken);
        setState({
          user,
          isAuthenticated: true,
          isLoading: false,
          error: null,
        });
        return true;
      }
      return false;
    },
    [],
  );

  const refreshSession = useCallback(async () => {
    const refreshed = await refreshTokens();
    if (!refreshed) {
      AuthStorage.clear();
      setState({
        user: null,
        isAuthenticated: false,
        isLoading: false,
        error: null,
      });
    }
  }, []);

  const handleTaraTokens = useCallback(
    (tokens: {
      accessToken: string;
      idToken: string;
      refreshToken: string;
    }): boolean => {
      const user = parseIdToken(tokens.idToken);
      if (user) {
        AuthStorage.setUser(user);
        AuthStorage.setAccessToken(tokens.accessToken);
        AuthStorage.setIdToken(tokens.idToken);
        AuthStorage.setRefreshToken(tokens.refreshToken);
        setState({
          user,
          isAuthenticated: true,
          isLoading: false,
          error: null,
        });
        return true;
      }
      return false;
    },
    [],
  );

  const value: AuthContextValue = {
    ...state,
    login,
    loginWithTara,
    logout,
    refreshSession,
    handleCodeCallback,
    handleTaraTokens,
    showLoginModal,
    setShowLoginModal,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextValue {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within AuthProvider");
  }
  return context;
}

