    it("renders description text", () => {
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      expect(
        screen.getByText(/Kopeeri ja jaga seda linki/),
      ).toBeInTheDocument();
    });

    it("URL input is readonly", () => {
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      expect(screen.getByLabelText("Jagamislink")).toHaveAttribute("readonly");
    });
  });

  describe("copy button", () => {
    it("shows copy button", () => {
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      expect(
        screen.getByRole("button", { name: "Kopeeri" }),
      ).toBeInTheDocument();
    });

    it("button is not disabled by default", () => {
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      expect(
        screen.getByRole("button", { name: "Kopeeri" }),
      ).not.toBeDisabled();
    });
  });

  describe("copy functionality", () => {
    it("copy button is clickable", async () => {
      const user = userEvent.setup();
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      const btn = screen.getByRole("button", { name: "Kopeeri" });
      expect(btn).not.toBeDisabled();
      // Note: clipboard API not available in jsdom, just verify button is interactive
      await user.click(btn);
    });

    it("does not close on copy click", async () => {
      const user = userEvent.setup();
      render(
        <ShareTaskModal
          isOpen={true}
          shareToken="abc123"
          taskName="Test Task"
          onClose={mockOnClose}
        />,
      );
      await user.click(screen.getByRole("button", { name: "Kopeeri" }));
      // onClose should not be called after copy attempt
      expect(mockOnClose).not.toHaveBeenCalled();
    });
  });
});

